# Definition for singly-linked list.
class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def detectCycle(self, head: ListNode) -> ListNode:
        if not head or not head.next:
            return None

        slow = head
        fast = head

        # Step 1: Detect if a cycle exists
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
            if slow == fast:
                break # Cycle detected
        else:
            # No cycle found (fast reached the end)
            return None

        # Step 2: Find the start of the cycle
        # Move slow to the head. Keep fast at the meeting point.
        # Move both one step at a time; they will meet at the cycle start.
        slow = head
        while slow != fast:
            slow = slow.next
            fast = fast.next

        return slow
